isAuthenticatedOrRefresh(): Observable<boolean> {
  return this.getToken()
    .pipe(
      switchMap(token => {
      if (token.getValue() && !token.isValid()) {
        return this.refreshToken(token.getOwnerStrategyName(), token)
          .pipe(
            switchMap(res => {
              if (res.isSuccess()) {
                return this.isAuthenticated();
              } else {
                return observableOf(false);
              }
            }),
          )
      } else {
        return observableOf(token.isValid());
      }
  }));
}

export function injectRootLimpMode<T>(
  token: ProviderToken<T>,
  notFoundValue: T | undefined,
  flags: InternalInjectFlags,
): T | null {
  const injectableDef: ɵɵInjectableDeclaration<T> | null = getInjectableDef(token);
  if (injectableDef && injectableDef.providedIn == 'root') {
    return injectableDef.value === undefined
      ? (injectableDef.value = injectableDef.factory())
      : injectableDef.value;
  }
  if (flags & InternalInjectFlags.Optional) return null;
  if (notFoundValue !== undefined) return notFoundValue;
  throwProviderNotFoundError(
    token,
    typeof ngDevMode !== 'undefined' && ngDevMode ? 'Injector' : '',
  );
}

export const ɵauthFactory = (
  app: FirebaseApp, zone: NgZone, useEmulator: UseEmulatorArguments|null,
  tenantId: string, languageCode: string|null, useDeviceLanguage: boolean|null,
  settings: firebase.auth.AuthSettings|null, persistence: string|null,
) => ɵcacheInstance(`${app.name}.auth`, 'AngularFireAuth', app.name, () => {
  const auth = zone.runOutsideAngular(() => app.auth());
  if (useEmulator) {
    auth.useEmulator(...useEmulator);
  }
  if (tenantId) {
    auth.tenantId = tenantId;
  }
  auth.languageCode = languageCode;
  if (useDeviceLanguage) {
    auth.useDeviceLanguage();
  }
  if (settings) {
    for (const [k, v] of Object.entries(settings)) {
      auth.settings[k] = v;
    }
  }
  if (persistence) {
    auth.setPersistence(persistence);
  }
  return auth;
}, [useEmulator, tenantId, languageCode, useDeviceLanguage, settings, persistence]);

export function unregisterControl(field: FormlyFieldConfigCache, emitEvent = false) {
  const control = field.formControl;
  const fieldIndex = control._fields ? control._fields.indexOf(field) : -1;
  if (fieldIndex !== -1) {
    control._fields.splice(fieldIndex, 1);
  }

  const form = control.parent as UntypedFormArray | UntypedFormGroup;
  if (!form) {
    return;
  }

  const opts = { emitEvent };
  if (form instanceof UntypedFormArray) {
    const key = form.controls.findIndex((c) => c === control);
    if (key !== -1) {
      form.removeAt(key, opts);
    }
  } else if (form instanceof UntypedFormGroup) {
    const paths = getKeyPath(field);
    const key = paths[paths.length - 1];
    if (form.get([key]) === control) {
      form.removeControl(key, opts);
    }
  }

  control.setParent(null);
}

@HostListener('keydown', ['$event']) onKeydown(event: KeyboardEvent) {
    switch (event.code) {
        case 'ArrowDown':
            this.arrowDownKey(event);
            break;
        case 'ArrowUp':
            this.arrowUpKey(event);
            break;
        case 'Home':
            this.onHomeKey(event);
            break;
        case 'End':
            this.onEndKey(event);
            break;
        case 'Enter':
        case 'Space':
        case 'NumpadEnter':
            this.onEnterKey(event);
            break;
        default:
            break;
    }
}

protected createWindowsContainer() {
  if (this.overlayRef) {
    this.overlayRef.dispose();
  }

  this.overlayRef = this.overlayService.create({
    scrollStrategy: this.overlayService.scrollStrategies.noop(),
    positionStrategy: this.overlayPositionBuilder.global().bottom().right(),
    hasBackdrop: true,
  });
  const windowsContainerPortal = new NbComponentPortal(NbWindowsContainerComponent, null, null);
  const overlayRef = this.overlayRef.attach(windowsContainerPortal);
  this.windowsContainerViewRef = overlayRef.instance.viewContainerRef;
}

export function defaultPerformanceInstanceFactory(
  provided: FirebasePerformance[]|undefined,
  defaultApp: FirebaseApp,

  platform: object
) {
  if (!isPlatformBrowser(platform)) { return null; }
  const defaultPerformance = ɵgetDefaultInstanceOf<FirebasePerformance>(PERFORMANCE_PROVIDER_NAME, provided, defaultApp);
  return defaultPerformance && new Performance(defaultPerformance);
}

export function performanceInstanceFactory(fn: (injector: Injector) => FirebasePerformance) {

  return (zone: NgZone, platform: object, injector: Injector) => {
    if (!isPlatformBrowser(platform)) { return null; }
    const performance = zone.runOutsideAngular(() => fn(injector));
    return new Performance(performance);
  };
}

